        padding: 10px 16px;
        text-align: center;
        border-bottom: 1px solid #eee;
      }

      tr:nth-child(even) {
        background-color: #fafafa;
      }

      tr:hover {
        background-color: #f1f7ff;
      }

      button {
        margin: 2px;
      }
    "))
  ),

  titlePanel("Truth Table Builder"),

  sidebarLayout(
    sidebarPanel(
      textInput("vars", "Variables:", "p q"),
      textInput("expr", "Expression:", ""),

      h4("Variables"),
      uiOutput("var_buttons"),

      h4("Connectives"),
      div(
        actionButton("not", "¬"),
        actionButton("and", "∧"),
        actionButton("or", "∨"),
        actionButton("imp", "→"),
        actionButton("iff", "↔")
      ),

      h4("Brackets"),
      div(
        actionButton("lpar", "("),
        actionButton("rpar", ")")
      ),

      br(),
      actionButton("clear", "Clear")
